/* ═══════════════════════════════════════════════════════════
   リズムクルーズ
   STAGE 1「4分ジャスト」スクロール譜面型ズレ判定UI。

   ・8小節 / 4分音符 / 4-4拍子 = 合計32拍
   ・4分音符が右から左へ流れ、中央の判定ラインに重なった瞬間にタップ
   ・タップ位置を判定ライン基準でマーカー表示（緑=JUST/青=EARLY/赤=LATE/灰=MISS）
   ・練習中はシンプルに（譜面・判定ライン・小節/状態・TAP・操作のみ）
   ・ズレ履歴グラフは練習中には出さず、8小節終了後の結果画面にまとめて表示
   ※ マイク入力・本格的なストローク音検出は未実装（タップで体験確認）
═══════════════════════════════════════════════════════════ */

const RHYTHM_CRUISE_VERSION = '0.12.93';
let audioContextDebugCreatedAt = null;
let audioContextDebugLastResumeAt = null;

/* vendor/ など同梱アセットの基準URL。script.js 自身のURL（document.currentScript.src）から
   ディレクトリ部分を取り出すため、通常版（rhythm-cruise/ 直下）でも PRO版
   （pro_a9f4k7q2m8z/ から ../script.js を参照）でも常に rhythm-cruise/ 直下を指す。
   これで vendor/vexflow.js が PRO版で 404 にならず、譜面UIが旧Canvasへフォールバックしない（v0.9.244）。 */
const RHYTHM_ASSET_BASE = (() => {
    try {
        const src = document.currentScript && document.currentScript.src;
        if (src) return src.replace(/[?#].*$/, '').replace(/[^/]*$/, '');
    } catch (_) { /* ignore */ }
    return '';
})();

function isProEdition() {
    return document.documentElement?.dataset?.appEdition === 'Pro';
}

function isStandardEdition() {
    return !isProEdition();
}

