    const med = (xs) => { const a = sorted(xs); return a.length ? a[Math.floor(a.length / 2)] : null; };
    const rows = (run && run.events || []).filter((e) => e.soundId === soundId).map((e) => hpEventOnsetDebug(e, focusFrom, focusTo));
