        if (lvl.noiseStatus === 'high') return { kind: 'warn', text: 'ノイズが大きいようです。静かな場所で確認してください' };
        if (lvl.status === 'ok') return { kind: 'ok', text: '音量は十分です。測定を開始できます' };
        if (lvl.status === 'weak') return { kind: 'warn', text: '音は入っていますが、波形が小さめです' };
