            androidBluetoothMicOffsetMs: mic.androidBluetoothMicOffsetMs || 0,
            micJudgeOffsetMs: micJudgeOffsetMs(),
            offsetDebug: androidJudgeOffsetDebug(),
            volumeTestReadiness: androidBtVolumeTest.volumeTestReadiness || null,
