async function copyCorrectionFlowLog() {
    const btn = els.correctionFlowLogCopy;
    if (btn) btn.disabled = true;
    const copiedAt = new Date().toISOString();
    const copySeq = ++correctionFlowCopySeq;
    let snapshot;
    try {
        snapshot = correctionFlowSnapshot('copy-button');
        if (snapshot) {
            snapshot.copyDebug = Object.assign(snapshot.copyDebug || {}, {
                copySeq,
                copiedAt,
                source: 'fresh-correctionFlowSnapshot',
            });
        }
    } catch (err) {
        recordCorrectionFlowError(err, 'copyCorrectionFlowLog.snapshot');
        snapshot = { version: RHYTHM_CRUISE_VERSION, error: errorForCorrectionFlowLog(err), copyDebug: { copySeq, copiedAt, source: 'fresh-correctionFlowSnapshot-error' } };
    }
    let text;
    try { text = JSON.stringify(snapshot, null, 2); }
    catch (err) {
        recordCorrectionFlowError(err, 'copyCorrectionFlowLog.stringify');
        text = JSON.stringify({ version: RHYTHM_CRUISE_VERSION, error: errorForCorrectionFlowLog(err), copyDebug: { copySeq, copiedAt } }, null, 2);
    }
    if (els.correctionFlowLogText) {
        els.correctionFlowLogText.value = text;
        els.correctionFlowLogText.classList.add('hidden');
    }
    let copied = false;
    try { copied = await copyTextToClipboard(text); } catch (err) { recordCorrectionFlowError(err, 'copyCorrectionFlowLog.clipboard'); copied = false; }
    if (els.correctionFlowLogStatus) {
        const seqLabel = snapshot && snapshot.snapshotSeq ? (' #' + snapshot.snapshotSeq + '-' + copySeq) : '';
        els.correctionFlowLogStatus.textContent = copied
            ? ('補正フロー状態ログをコピーしました' + seqLabel + '。')
            : ('自動コピーできませんでした' + seqLabel + '。下のログを長押ししてコピーしてください。');
    }
    if (!copied && els.correctionFlowLogText) {
        els.correctionFlowLogText.classList.remove('hidden');
    }
    if (btn) {
        btn.disabled = false;
        btn.style.opacity = '';
    }
}

window.addEventListener('error', (event) => recordCorrectionFlowError(event.error || new Error(event.message), 'window.error'));
window.addEventListener('unhandledrejection', (event) => recordCorrectionFlowError(event.reason, 'window.unhandledrejection'));
function fitPtLane() {
    if (!els.ptLaneCanvas) return;
    // CSS高さを固定し、fitOne() はその値をDPR変換するだけにする。
    // clientHeightを親要素から再帰的に拾わないので、スクロールしても高さが増え続けない。
    els.ptLaneCanvas.style.width = '100%';
    els.ptLaneCanvas.style.height = PT_LANE_HEIGHT + 'px';
    ptLane = fitOne(els.ptLaneCanvas);
}

function ptDetectionThreshold() {
    // 実践テストはSTAGEと同じ検出にするため、マイク感度カーブ補正後の実効しきい値を使う（v0.9.140）。
    // ただしクリック音入力テストはクリック専用しきい値を直接使い、Practice用感度カーブから分離する。
    if (bt.active && bt.debug) return bt.debug.thresholdDuringClickInputTest;
    let mult = micSensitivityMultiplier();
    return mic.threshold * mult * MIC_STAGE_DETECT_FACTOR;
}

function isAndroidNormalMicFlow() {
    return selectedTestPlatform === 'android' && androidAudioProbeDeviceInfo().isAndroid && isNormalMicInput();
}
/* v0.12.71：Android仮（iPhone式・android_ios_style_trial）の通常マイクを、実機Androidで判定する。
   Android本番（isAndroidNormalMicFlow）と同じく androidBuiltinMicOffsetMs を保存先とし、
   遅延補正の窓/波形表示反映・クリック音量の反応ライン安全制御を同等に適用するためのゲート。
   iPhone・Androidイヤホン系・Android仮イヤホン系は対象外。 */
function isAndroidTrialNormalMicOnDevice() {
    return isAndroidIphoneStyleTrialFlow() && isNormalMicInput() && androidAudioProbeDeviceInfo().isAndroid;
}
function isAndroidNormalMicClickSafetyFlow() {
    return isAndroidNormalMicFlow() || isAndroidTrialNormalMicOnDevice();
}
function isIosNewNormalMicClickSafetyFlow() {
    return isIosNewProductionFlow() && isNormalMicInput() && !isHeadphoneInput();
}

function freshFinalCheckClickDebug(originalVolume, usedVolume) {
    try {
        const saved = Number(mic.androidBuiltinMicOffsetMs);
        const delayedGuardMs = Number.isFinite(saved) && saved < 0 ? Math.min(800, Math.max(0, -saved)) : 0;
        return Object.assign({
            inputType: getMicInputType(),
            selectedTestPlatform,
            androidDevice: !!androidAudioProbeDeviceInfo().isAndroid,
            originalClickVolume: originalVolume,
            usedClickVolume: usedVolume,
            threshold: mic.threshold,
            detectThreshold: ptDetectionThreshold(),
            clickPeakGain: clickPeakGain(),
            clickGuardMs: mic.clickGuardMs,
            delayedClickGuardMs: delayedGuardMs,
            maxNearClickPeak: 0,
            maxDelayedClickPeak: 0,
            maxPeakOverThresholdNearClick: 0,
        }, androidNormalMicClickLimiterDebug());
    } catch (err) {
        recordCorrectionFlowError(err, 'freshFinalCheckClickDebug');
        return {
            originalClickVolume: originalVolume,
            usedClickVolume: usedVolume,
            delayedClickGuardMs: null,
            debugError: errorForCorrectionFlowLog(err),
            maxNearClickPeak: 0,
            maxDelayedClickPeak: 0,
            maxPeakOverThresholdNearClick: 0,
        };
    }
}

function updateFinalCheckClickDebug(now, peak, threshold) {
    const d = pt.clickDebug;
    if (!d) return;
    const latest = ptLatestClickPerf(now);
    if (latest <= -99999) return;
    const sinceClick = now - latest;
    const inDirectWindow = sinceClick >= 0 && sinceClick <= Math.max(120, mic.clickGuardMs || 0);
    const delayed = d.delayedClickGuardMs || 0;
    const delayedDelta = delayed > 0 ? Math.abs(sinceClick - delayed) : Infinity;
    const inDelayedWindow = delayed > 0 && delayedDelta <= 120;
    if (inDirectWindow && peak > d.maxNearClickPeak) d.maxNearClickPeak = peak;
    if (inDelayedWindow && peak > d.maxDelayedClickPeak) d.maxDelayedClickPeak = peak;
    if ((inDirectWindow || inDelayedWindow) && peak >= threshold && peak > d.maxPeakOverThresholdNearClick) {
        d.maxPeakOverThresholdNearClick = peak;
    }
}

function freshAndroidNormalMicInitialClickGate() {
    const enabled = isAndroidNormalMicClickSafetyFlow();
    return {
        androidNormalMicFinalInitialClickGateEnabled: enabled,
        androidNormalMicFinalInitialClickGateStatus: enabled ? 'waiting' : 'disabled',
        androidNormalMicFinalInitialClickNearPeak: 0,
        androidNormalMicFinalInitialClickDelayedPeak: 0,
        androidNormalMicFinalInitialClickPeakUsed: 0,
        androidNormalMicFinalInitialClickDetectLine: ptDetectionThreshold(),
        androidNormalMicFinalInitialClickRatioToLine: null,
        androidNormalMicFinalInitialClickPass: null,
        androidNormalMicFinalInitialClickAction: enabled ? 'continue-if-safe' : 'none',
        androidNormalMicFinalInitialClickReason: enabled ? 'initial-click-only-count-in' : 'not-android-normal-mic',
        androidNormalMicFinalInitialClickSuggestedAction: null,
    };
}

function updateAndroidNormalMicInitialClickGate(now, peak) {
    const gate = pt.initialClickGate;
    if (!gate || !gate.androidNormalMicFinalInitialClickGateEnabled || gate.evaluated) return;
    if (gate.startedAtPerf != null && now < gate.startedAtPerf) return;
    if (gate.endsAtPerf != null && now > gate.endsAtPerf) return;
    const latest = ptLatestClickPerf(now);
    if (latest <= -99999) return;
    const sinceClick = now - latest;
    const nearTo = Math.max(120, mic.clickGuardMs || 0);
    if (sinceClick >= 0 && sinceClick <= nearTo && peak > gate.androidNormalMicFinalInitialClickNearPeak) {
        gate.androidNormalMicFinalInitialClickNearPeak = peak;
    }
    const delayed = (pt.clickDebug && pt.clickDebug.delayedClickGuardMs) || 0;
    if (delayed > 0 && Math.abs(sinceClick - delayed) <= 120 && peak > gate.androidNormalMicFinalInitialClickDelayedPeak) {
        gate.androidNormalMicFinalInitialClickDelayedPeak = peak;
    }
}

function finalizeAndroidNormalMicInitialClickGate(action) {
    const gate = pt.initialClickGate;
    if (!gate || !gate.androidNormalMicFinalInitialClickGateEnabled || gate.evaluated) return null;
    const line = ptDetectionThreshold();
    const peakUsed = Math.max(
        Number(gate.androidNormalMicFinalInitialClickNearPeak) || 0,
        Number(gate.androidNormalMicFinalInitialClickDelayedPeak) || 0,
    );
    const ratio = line > 0 ? peakUsed / line : null;
    const pass = ratio == null || ratio <= 0.9;
    gate.evaluated = true;
    gate.androidNormalMicFinalInitialClickDetectLine = line;
    gate.androidNormalMicFinalInitialClickPeakUsed = peakUsed;
    gate.androidNormalMicFinalInitialClickRatioToLine = ratio;
    gate.androidNormalMicFinalInitialClickPass = pass;
    gate.androidNormalMicFinalInitialClickGateStatus = pass ? 'passed' : 'failed';
    gate.androidNormalMicFinalInitialClickAction = pass ? 'continue-to-stroke' : (action || 'stop-before-stroke');
    gate.androidNormalMicFinalInitialClickReason = pass
        ? 'click-leak-under-90pct-detect-line'
        : 'click-leak-over-90pct-detect-line';
    gate.androidNormalMicFinalInitialClickSuggestedAction = pass
        ? null
        : 'device-volume-down-and-retry-mic-reaction-test';
    return gate;
}

function androidNormalMicInitialClickGateSnapshot() {
    const gate = pt.initialClickGate;
    if (!gate) return null;
    const out = {};
    [
        'androidNormalMicFinalInitialClickGateEnabled',
        'androidNormalMicFinalInitialClickGateStatus',
        'androidNormalMicFinalInitialClickNearPeak',
        'androidNormalMicFinalInitialClickDelayedPeak',
        'androidNormalMicFinalInitialClickPeakUsed',
        'androidNormalMicFinalInitialClickDetectLine',
        'androidNormalMicFinalInitialClickRatioToLine',
        'androidNormalMicFinalInitialClickPass',
        'androidNormalMicFinalInitialClickAction',
        'androidNormalMicFinalInitialClickReason',
        'androidNormalMicFinalInitialClickSuggestedAction',
    ].forEach((key) => { out[key] = gate[key]; });
    return out;
}

