    // 小節数の−/＋（v0.9.118）：候補 1/2/4/8 を行き来する
    if (els.barsUp) els.barsUp.addEventListener('click', () => stepStageBars(+1));
    if (els.barsDown) els.barsDown.addEventListener('click', () => stepStageBars(-1));
